// Jenkinsfile - Secure declarative pipeline
// RECOMMENDED: Use declarative syntax (sandboxed by default)

@Library('secure-shared-library@v1.2.3') _  // Pin library version

pipeline {
    agent {
        docker {
            image 'node:18-alpine'
            args '--read-only --tmpfs /tmp --security-opt=no-new-privileges'
        }
    }

    options {
        // Security options
        timestamps()
        timeout(time: 30, unit: 'MINUTES')
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '10'))
    }

    parameters {
        // SECURE: Use choice parameters instead of free-text input
        choice(
            name: 'DEPLOY_ENV',
            choices: ['dev', 'staging', 'production'],
            description: 'Target deployment environment'
        )
        booleanParam(
            name: 'RUN_TESTS',
            defaultValue: true,
            description: 'Execute test suite'
        )
    }

    environment {
        // SECURE: Use Jenkins credentials store, never hardcode
        AWS_CREDENTIALS = credentials('aws-deploy-key')
        NPM_TOKEN = credentials('npm-publish-token')

        // Prevent credential leakage in logs
        GIT_ASKPASS = 'echo'
        GIT_TERMINAL_PROMPT = '0'
    }

    stages {
        stage('Checkout') {
            steps {
                // SECURE: Explicit checkout with depth limit
                checkout([
                    $class: 'GitSCM',
                    branches: [[name: "${env.GIT_BRANCH}"]],
                    extensions: [
                        [$class: 'CloneOption', depth: 1, shallow: true],
                        [$class: 'CleanBeforeCheckout']
                    ],
                    userRemoteConfigs: [[
                        credentialsId: 'github-ssh-key',
                        url: 'git@github.com:org/repo.git'
                    ]]
                ])
            }
        }

        stage('Build') {
            steps {
                script {
                    // SECURE: Input validation for user parameters
                    if (!(params.DEPLOY_ENV in ['dev', 'staging', 'production'])) {
                        error "Invalid deployment environment: ${params.DEPLOY_ENV}"
                    }
                }

                // SECURE: Use sh with explicit arguments, avoid string interpolation
                sh label: 'Install dependencies', script: '''
                    set -euo pipefail
                    npm ci --prefer-offline --no-audit
                '''

                sh label: 'Build application', script: '''
                    set -euo pipefail
                    npm run build
                '''
            }
        }

        stage('Security Scan') {
            parallel {
                stage('SAST') {
                    steps {
                        sh 'npm audit --production --audit-level=moderate'
                    }
                }
                stage('Container Scan') {
                    steps {
                        sh '''
                            docker run --rm \
                                -v $(pwd):/workspace \
                                aquasec/trivy:latest \
                                filesystem --severity HIGH,CRITICAL /workspace
                        '''
                    }
                }
            }
        }

        stage('Deploy') {
            when {
                expression { params.DEPLOY_ENV == 'production' }
                branch 'main'
            }
            steps {
                // SECURE: Use input for manual approval
                input(
                    message: "Deploy to production?",
                    ok: "Deploy",
                    submitter: "admin,deploy-team"
                )

                // SECURE: Use credential binding, not environment variables
                withCredentials([[
                    $class: 'AmazonWebServicesCredentialsBinding',
                    credentialsId: 'aws-production',
                    accessKeyVariable: 'AWS_ACCESS_KEY_ID',
                    secretKeyVariable: 'AWS_SECRET_ACCESS_KEY'
                ]]) {
                    sh label: 'Deploy to S3', script: '''
                        set -euo pipefail
                        aws s3 sync dist/ s3://production-bucket/ --delete
                    '''
                }
            }
        }
    }

    post {
        always {
            // Clean workspace to prevent credential leakage
            cleanWs(
                deleteDirs: true,
                patterns: [[
                    pattern: '.git',
                    type: 'INCLUDE'
                ]]
            )
        }
        failure {
            emailext(
                subject: "Build Failed: ${env.JOB_NAME} #${env.BUILD_NUMBER}",
                body: "Check console output at ${env.BUILD_URL}",
                to: "${env.CHANGE_AUTHOR_EMAIL}"
            )
        }
    }
}

// VULNERABLE EXAMPLE - DO NOT USE
// Scripted pipeline with code injection risk:
// node {
//     // VULNERABLE: User input directly in shell command
//     def userInput = input(message: 'Enter branch name')
//     sh "git checkout ${userInput}"  // Injection risk!
//     
//     // VULNERABLE: Eval of user-provided Groovy code
//     def command = params.CUSTOM_COMMAND
//     evaluate(command)  // Arbitrary code execution!
// }
